  ('fire-eq-tech-moex-02200', 'fire-eq-tech', 'fire-eq-tech-moex-102-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法規定，六類公共危險物品製造場所，其外牆 與廠區外鄰近場所之安全距離，下列敍述何者錯誤？', '["與古蹟之距離，應在五十公尺以上", "與博物館之距離，應在五十公尺以上", "與加油站之距離，應在三十公尺以上", "與爆竹製造工廠之距離，應在二十公尺以上"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:23+00:00", "source_pdf_sha1": "0a34ee03f2ae", "answer_pdf_sha1": "d13e51cedf0e", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "902", "s": "0708", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規概要", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
